const fs = require('fs');
const path = require('path');

const pathsToTest = [
  './products.json',
  './data/products.json',
  './files/products.json',
  './.n8n/products.json',
  '/home/node/.n8n/products.json'
];

const results = [];

for (const p of pathsToTest) {
  let writable = false;
  let error = null;
  try {
    const absPath = path.resolve(p);
    const dir = path.dirname(absPath);
    // Check if directory exists and is writable
    fs.accessSync(dir, fs.constants.W_OK);
    writable = true;
  } catch (e) {
    error = e.message;
  }
  results.push({ path: p, absPath: path.resolve(p), writable, error });
}

return { 
  whoami: process.env.USER || 'unknown', 
  cwd: process.cwd(),
  results 
};
